// Generated by AI (UnitTest MCP)
//! Facade over the design-item bridge (ADR-0023): register an ADR for review,
//! read the Design Board, and the human accept/reject decision that completes
//! design work without code conformance.

use crate::design::{design_id_from_path, DesignItem, DesignMetadata, DesignStatus};
use crate::{now_unix, Lodestar, LodestarError, Result};

impl Lodestar {
    /// Register an ADR as a design item under review. It is *proposed* (tainted)
    /// until a human decides it: invisible to `next_task` and the executive
    /// board, present on the Design Board.
    pub fn register_design(
        &self,
        adr_path: &str,
        title: &str,
        summary: &str,
    ) -> Result<DesignItem> {
        let adr_path = adr_path.replace('\\', "/");
        let id = design_id_from_path(&adr_path);
        self.store.register_design_item(
            &id,
            &adr_path,
            title,
            summary,
            self.agent.as_deref(),
            now_unix(),
        )
    }

    /// Reconcile structured repository ADR metadata without inferring or
    /// scheduling implementation work. Existing durable decisions always win.
    pub fn reconcile_designs(&self, entries: &[DesignMetadata]) -> Result<Vec<DesignItem>> {
        let now = now_unix();
        let mut reconciled = Vec::with_capacity(entries.len());
        for entry in entries {
            let adr_path = entry.adr_path.trim().replace('\\', "/");
            if adr_path.is_empty() || entry.title.trim().is_empty() {
                return Err(LodestarError::Invalid(
                    "reconciled ADR metadata requires a path and title".to_string(),
                ));
            }
            reconciled.push(self.store.reconcile_design_item(
                &DesignMetadata {
                    adr_path,
                    title: entry.title.trim().to_string(),
                    summary: entry.summary.trim().to_string(),
                    status: entry.status,
                    proposed_by: entry.proposed_by.clone(),
                },
                now,
            )?);
        }
        Ok(reconciled)
    }

    /// The actionable Design Board: proposed decisions plus accepted designs
    /// whose implementation promotion is pending or retryable.
    pub fn design_board(&self) -> Result<Vec<DesignItem>> {
        self.store.actionable_design_items()
    }

    /// Every design item (durable audit view), or those in one status.
    pub fn list_design_items(&self, status: Option<DesignStatus>) -> Result<Vec<DesignItem>> {
        self.store.list_design_items(status)
    }

    /// Human acceptance — the attributed, guarded human decision *only*
    /// (ADR-0023). The design becomes `accepted` with promotion `pending`; it
    /// does **not** run ADR-0009 code conformance and does **not** invoke a
    /// model or create tasks. Materialising the work is the separate, idempotent
    /// `promote_design` step, so an optional model call never runs inside the
    /// acceptance write. No agent may accept its own design (human-in-the-loop).
    pub fn accept_design(&self, id: &str, human: &str) -> Result<DesignItem> {
        let human = human.trim();
        self.load_for_decision(id, human)?;
        let won =
            self.store
                .decide_design_item(id, DesignStatus::Accepted, human, None, now_unix())?;
        if !won {
            return Err(LodestarError::Invalid(format!(
                "design item {id} was decided concurrently"
            )));
        }
        self.store
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))
    }

    /// Human rejection — durable and auditable (archive-not-delete); spawns no
    /// work. Requires a rationale.
    pub fn reject_design(&self, id: &str, human: &str, reason: &str) -> Result<DesignItem> {
        if reason.trim().is_empty() {
            return Err(LodestarError::Invalid(
                "a rejection reason is required".to_string(),
            ));
        }
        let human = human.trim();
        self.load_for_decision(id, human)?;
        let won = self.store.decide_design_item(
            id,
            DesignStatus::Rejected,
            human,
            Some(reason),
            now_unix(),
        )?;
        if !won {
            return Err(LodestarError::Invalid(format!(
                "design item {id} was decided concurrently"
            )));
        }
        self.store
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))
    }

    /// Load a design item and enforce the human-decision guards: a non-empty
    /// human identity that is not the proposing agent (human-in-the-loop), and an
    /// item still open to a decision.
    fn load_for_decision(&self, id: &str, human: &str) -> Result<DesignItem> {
        if human.is_empty() {
            return Err(LodestarError::Invalid(
                "a human decider identity is required".to_string(),
            ));
        }
        let item = self
            .store
            .get_design_item(id)?
            .ok_or_else(|| LodestarError::NotFound(id.to_string()))?;
        // Human-in-the-loop: the agent that proposed a design may not decide it.
        if item.proposed_by.as_deref() == Some(human) {
            return Err(LodestarError::Invalid(
                "an agent may not decide its own design item; a human reviewer must accept or reject it"
                    .to_string(),
            ));
        }
        if !item.status.is_open() {
            return Err(LodestarError::Invalid(format!(
                "design item {id} is already {}; only a proposed item can be decided",
                item.status.as_str()
            )));
        }
        Ok(item)
    }
}

#[cfg(test)]
mod tests {
    use crate::design::{
        DesignConstraintDraft, DesignMaterializationMode, DesignMaterializationPlan,
        DesignMetadata, DesignTaskDraft,
    };
    use crate::facade::test_support::engine;
    use crate::{DesignPromotionStatus, DesignStatus, GoalKind, Lodestar, LodestarError};

    fn agent_engine(agent: &str) -> Lodestar {
        engine().with_agent(Some(agent.to_string()))
    }

    fn create_plan(goal_id: &str, title: &str) -> DesignMaterializationPlan {
        DesignMaterializationPlan {
            mode: DesignMaterializationMode::Create,
            tasks: vec![DesignTaskDraft {
                goal_id: goal_id.to_string(),
                title: title.to_string(),
                acceptance: "reviewed acceptance".to_string(),
            }],
            task_ids: Vec::new(),
            constraints: Vec::new(),
            rationale: None,
        }
    }

    #[test]
    fn accept_marks_pending_and_promote_materialises_tasks_idempotently() {
        let e = agent_engine("planner");
        let item = e
            .register_design(
                "docs/adr/0023-design-board-accept-bridge.md",
                "Accept bridge",
                "human accept completes design work",
            )
            .unwrap();
        assert_eq!(item.id, "design:0023-design-board-accept-bridge");
        assert_eq!(item.status, DesignStatus::Proposed);
        assert_eq!(item.promotion_status, DesignPromotionStatus::NotRequired);
        assert_eq!(item.proposed_by.as_deref(), Some("planner"));
        assert_eq!(e.design_board().unwrap().len(), 1);

        // Accept is the human decision only: no code conformance, no tasks yet,
        // promotion armed `pending`.
        let accepted = e.accept_design(&item.id, "human-reviewer").unwrap();
        assert_eq!(accepted.status, DesignStatus::Accepted);
        assert_eq!(accepted.decided_by.as_deref(), Some("human-reviewer"));
        assert_eq!(accepted.promotion_status, DesignPromotionStatus::Pending);
        assert!(e.next_task().unwrap().is_none());
        assert_eq!(e.design_board().unwrap(), vec![accepted.clone()]);
        assert!(e.design_promotion(&item.id).unwrap().is_none());

        // The human selects an objective, reviews the plan, then materialises it.
        let objective = e
            .define_goal(GoalKind::Objective, "Ship the bridge", "wire it", None)
            .unwrap();
        let plan = e.plan_design_promotion(&item.id, &objective.id).unwrap();
        assert!(e.next_task().unwrap().is_none());
        let promo = e.promote_design(&item.id, &plan).unwrap();
        assert_eq!(
            promo.item.promotion_status,
            DesignPromotionStatus::Materialized
        );
        assert_eq!(promo.goals[0].id, objective.id);
        assert!(!promo.tasks.is_empty());
        assert!(promo.tasks.iter().all(|t| t.goal_id == objective.id));
        assert_eq!(e.next_task().unwrap().unwrap().goal_id, objective.id);
        assert!(e.design_board().unwrap().is_empty());
        let persisted = e.design_promotion(&item.id).unwrap().unwrap();
        assert_eq!(persisted.goals[0].id, promo.goals[0].id);
        assert_eq!(
            persisted
                .tasks
                .iter()
                .map(|task| &task.id)
                .collect::<Vec<_>>(),
            promo.tasks.iter().map(|task| &task.id).collect::<Vec<_>>()
        );

        // Idempotent: a retry returns the same tasks, creating no duplicates.
        let again = e.promote_design(&item.id, &plan).unwrap();
        assert_eq!(
            again.tasks.iter().map(|t| t.id.clone()).collect::<Vec<_>>(),
            promo.tasks.iter().map(|t| t.id.clone()).collect::<Vec<_>>()
        );
        assert_eq!(e.design_materialization_history(&item.id).unwrap().len(), 1);
    }

    #[test]
    fn promote_requires_an_accepted_design_and_an_objective_target() {
        let e = agent_engine("planner");
        let item = e.register_design("docs/adr/0031-x.md", "X", "x").unwrap();
        let objective = e
            .define_goal(GoalKind::Objective, "Obj", "o", None)
            .unwrap();
        // A proposed (not yet accepted) design cannot be planned or promoted.
        assert!(e.plan_design_promotion(&item.id, &objective.id).is_err());
        assert!(e
            .promote_design(&item.id, &create_plan(&objective.id, "Implement X"))
            .is_err());
        e.accept_design(&item.id, "reviewer").unwrap();
        // A constraint goal is not a valid promotion target.
        let constraint = e.define_goal(GoalKind::Constraint, "C", "c", None).unwrap();
        assert!(e
            .promote_design(&item.id, &create_plan(&constraint.id, "Invalid task"))
            .is_err());
    }

    #[test]
    fn an_agent_cannot_decide_its_own_design() {
        let e = agent_engine("planner");
        let item = e
            .register_design("docs/adr/0099-self.md", "Self", "no self-accept")
            .unwrap();
        let err = e.accept_design(&item.id, "planner").unwrap_err();
        assert!(matches!(err, LodestarError::Invalid(_)));
        // Nothing changed: still proposed, still on the board.
        assert_eq!(e.design_board().unwrap().len(), 1);
    }

    #[test]
    fn a_decided_item_cannot_be_decided_again() {
        let e = agent_engine("planner");
        let item = e
            .register_design("docs/adr/0100-twice.md", "Twice", "")
            .unwrap();
        e.accept_design(&item.id, "human").unwrap();
        let err = e
            .reject_design(&item.id, "human", "changed my mind")
            .unwrap_err();
        assert!(matches!(err, LodestarError::Invalid(_)));
    }

    #[test]
    fn promote_registers_mandated_constraints_into_the_constitution() {
        let e = agent_engine("planner");
        let item = e
            .register_design(
                "docs/adr/0030-typed-errors.md",
                "Typed errors everywhere",
                "all fallible IO returns a typed error",
            )
            .unwrap();
        e.accept_design(&item.id, "reviewer").unwrap();
        let objective = e
            .define_goal(GoalKind::Objective, "Type the errors", "do it", None)
            .unwrap();
        let mut plan = create_plan(&objective.id, "Type the errors");
        plan.constraints.push(DesignConstraintDraft {
            kind: GoalKind::Constraint,
            title: "No unwrap in prod".to_string(),
            statement: "no unwrap()/expect() on fallible IO outside tests".to_string(),
        });
        let promo = e.promote_design(&item.id, &plan).unwrap();
        // The mandated constraint was registered as a normative goal...
        assert_eq!(promo.constraints.len(), 1);
        assert_eq!(promo.constraints[0].kind, GoalKind::Constraint);
        // ...and it is now part of the active constitution conformance enforces.
        assert!(e
            .get_constitution()
            .unwrap()
            .iter()
            .any(|g| g.title == "No unwrap in prod"));
        // The objective work was materialised alongside it.
        assert!(!promo.tasks.is_empty());
    }

    #[test]
    fn link_and_no_work_materializations_create_no_duplicate_tasks() {
        let e = agent_engine("planner");
        let first_goal = e
            .define_goal(GoalKind::Objective, "Existing graph work", "graph", None)
            .unwrap();
        let second_goal = e
            .define_goal(GoalKind::Objective, "Existing intent work", "intent", None)
            .unwrap();
        let graph_task = e
            .create_task(&first_goal.id, "Existing graph task", "done")
            .unwrap();
        let intent_task = e
            .create_task(&second_goal.id, "Existing intent task", "done")
            .unwrap();
        let item = e
            .register_design("docs/adr/0103-link.md", "Link", "reuse existing work")
            .unwrap();
        e.accept_design(&item.id, "reviewer").unwrap();
        let linked = e
            .promote_design(
                &item.id,
                &DesignMaterializationPlan {
                    mode: DesignMaterializationMode::Link,
                    tasks: Vec::new(),
                    task_ids: vec![graph_task.id.clone(), intent_task.id.clone()],
                    constraints: Vec::new(),
                    rationale: Some("These tasks already implement the decision".into()),
                },
            )
            .unwrap();
        assert_eq!(linked.tasks.len(), 2);
        assert_eq!(linked.goals.len(), 2);
        assert_eq!(e.board(false).unwrap().len(), 2);

        let no_work = e
            .register_design("docs/adr/0104-no-work.md", "No work", "policy only")
            .unwrap();
        e.accept_design(&no_work.id, "reviewer").unwrap();
        let resolved = e
            .promote_design(
                &no_work.id,
                &DesignMaterializationPlan {
                    mode: DesignMaterializationMode::NoWork,
                    tasks: Vec::new(),
                    task_ids: Vec::new(),
                    constraints: Vec::new(),
                    rationale: Some("Existing behavior already conforms".into()),
                },
            )
            .unwrap();
        assert!(resolved.tasks.is_empty());
        assert!(resolved.goals.is_empty());
        assert_eq!(e.board(false).unwrap().len(), 2);
    }

    #[test]
    fn repair_relinks_current_work_and_keeps_append_only_history() {
        let e = agent_engine("planner");
        let goal = e
            .define_goal(GoalKind::Objective, "Repair promotion", "repair", None)
            .unwrap();
        let existing = e
            .create_task(&goal.id, "Authoritative existing task", "done")
            .unwrap();
        let item = e
            .register_design("docs/adr/0105-repair.md", "Repair", "review repair")
            .unwrap();
        e.accept_design(&item.id, "reviewer").unwrap();
        let first = e
            .promote_design(&item.id, &create_plan(&goal.id, "Generated duplicate"))
            .unwrap();
        let duplicate_id = first.tasks[0].id.clone();
        let repair = DesignMaterializationPlan {
            mode: DesignMaterializationMode::Link,
            tasks: Vec::new(),
            task_ids: vec![existing.id.clone()],
            constraints: Vec::new(),
            rationale: Some("The reviewed work already existed".into()),
        };
        let revised = e
            .revise_design_promotion(&item.id, "second-reviewer", &repair)
            .unwrap();
        assert_eq!(revised.revision, 2);
        assert_eq!(revised.tasks[0].id, existing.id);
        assert!(e
            .board(true)
            .unwrap()
            .iter()
            .any(|task| task.id == duplicate_id));
        assert_eq!(e.design_materialization_history(&item.id).unwrap().len(), 2);

        let retry = e
            .revise_design_promotion(&item.id, "second-reviewer", &repair)
            .unwrap();
        assert_eq!(retry.revision, 2);
        assert_eq!(e.design_materialization_history(&item.id).unwrap().len(), 2);
    }

    #[test]
    fn reject_requires_a_reason_and_stays_durable() {
        let e = agent_engine("planner");
        let item = e
            .register_design("docs/adr/0101-reject.md", "Reject", "")
            .unwrap();
        assert!(e.reject_design(&item.id, "human", "  ").is_err());
        let rejected = e
            .reject_design(&item.id, "human", "superseded by 0102")
            .unwrap();
        assert_eq!(rejected.status, DesignStatus::Rejected);
        assert_eq!(rejected.reason.as_deref(), Some("superseded by 0102"));
        // Archive-not-delete: off the board but still present.
        assert!(e.design_board().unwrap().is_empty());
        assert_eq!(e.list_design_items(None).unwrap().len(), 1);
    }

    #[test]
    fn registering_the_same_adr_twice_is_rejected() {
        let e = agent_engine("planner");
        e.register_design("docs/adr/0102-dup.md", "Dup", "")
            .unwrap();
        let err = e
            .register_design("docs/adr/0102-dup.md", "Dup again", "")
            .unwrap_err();
        assert!(matches!(err, LodestarError::Invalid(_)));
    }

    #[test]
    fn reconciliation_imports_history_without_scheduling_or_overwriting_decisions() {
        let e = agent_engine("workspace-sensor");
        let entries = vec![
            DesignMetadata {
                adr_path: "docs\\adr\\0026-constitution.md".into(),
                title: "Constitution".into(),
                summary: "review governance".into(),
                status: DesignStatus::Proposed,
                proposed_by: Some("planner".into()),
            },
            DesignMetadata {
                adr_path: "docs/adr/0001-historical.md".into(),
                title: "Historical".into(),
                summary: String::new(),
                status: DesignStatus::Accepted,
                proposed_by: None,
            },
            DesignMetadata {
                adr_path: "docs/adr/0002-rejected.md".into(),
                title: "Rejected".into(),
                summary: String::new(),
                status: DesignStatus::Rejected,
                proposed_by: None,
            },
        ];

        let reconciled = e.reconcile_designs(&entries).unwrap();
        assert_eq!(reconciled.len(), 3);
        assert_eq!(reconciled[0].adr_path, "docs/adr/0026-constitution.md");
        assert!(reconciled
            .iter()
            .all(|item| item.promotion_status == DesignPromotionStatus::NotRequired));
        assert_eq!(e.design_board().unwrap(), vec![reconciled[0].clone()]);
        assert!(e.next_task().unwrap().is_none());

        let accepted = e.accept_design(&reconciled[0].id, "reviewer").unwrap();
        let retry = e
            .reconcile_designs(&[DesignMetadata {
                status: DesignStatus::Rejected,
                title: "Must not overwrite".into(),
                ..entries[0].clone()
            }])
            .unwrap();
        assert_eq!(retry, vec![accepted.clone()]);
        assert_eq!(e.design_board().unwrap(), vec![accepted]);
        assert!(e.next_task().unwrap().is_none());
    }
}
